package modules

import (
	"fmt"
	"html"
	"strconv"
	"strings"

	tg "github.com/amarnathcjd/gogram/telegram"
)

const piDigits1000 = "3."

func PiDigitsHandler(m *tg.NewMessage) error {
	args := strings.Fields(m.Args())
	n := 50
	if len(args) >= 1 {
		raw := strings.TrimSpace(args[0])
		v, err := strconv.Atoi(raw)
		if err != nil {
			_, e := m.Reply("Invalid N: <code>" + html.EscapeString(raw) + "</code>\nProvide a positive integer (1-1000).")
			return e
		}
		if v < 1 {
			_, e := m.Reply("N must be at least 1.")
			return e
		}
		if v > 1000 {
			_, e := m.Reply("N too large. Max digits is <b>1000</b>.")
			return e
		}
		n = v
	}

	digits := strings.ReplaceAll(piDigits1000, ".", "")
	digits = digits[:n]

	var out string
	if n == 1 {
		out = digits
	} else {
		out = digits[:1] + "." + digits[1:]
	}

	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("<b>Pi to %d digit%s</b>\n\n", n, pluralizeS(n)))
	sb.WriteString("<code>" + out + "</code>")

	_, err := m.Reply(sb.String())
	return err
}

func pluralizeS(n int) string {
	if n == 1 {
		return ""
	}
	return "s"
}

func registerPiDigitsHandlers() {
	c := Client
	c.On("cmd:pi", PiDigitsHandler)
}

func init() {
	QueueHandlerRegistration(registerPiDigitsHandlers)
}
